//Rtk add
snmp_com2sec_t *snmpScanPtr = NULL, *snmpComList = NULL;

void snmp_community_removeAll(void)
{
    snmp_com2sec_t *pTmp = NULL;
    snmp_com2sec_t *prev = NULL;
    pTmp = snmpComList;
    while (pTmp)
    {
        prev = pTmp;
        pTmp = pTmp->next;
        SNMP_FREE(prev);
    }
    snmpComList = NULL;
}

void snmp_community_scanAccessInit(void)
{
    snmpScanPtr  = snmpComList;
}


snmp_com2sec_t *snmp_community_scanFirst(void)
{
    return snmpComList;
}

snmp_com2sec_t *snmp_community_scanAccessNext(void)
{
    snmp_com2sec_t *returnval = snmpScanPtr;
    if (snmpScanPtr)
        snmpScanPtr  = snmpScanPtr->next;
    return returnval;
}

snmp_com2sec_t *snmp_communityEntry_get(char *pComName)
{
    if (NULL == pComName)
        return NULL;

    snmpScanPtr  = snmpComList;
    while(snmpScanPtr)
    {
        if ( 0 == osal_strcmp(pComName, snmpScanPtr->comEntry.comName))
            return snmpScanPtr;

        snmpScanPtr = snmpScanPtr->next;
    }

    return NULL;
}

int32 snmp_community_creatEntry(sal_snmp_com2sec_t *pEntry)
{
    snmp_com2sec_t *entry;
    snmp_com2sec_t *pTmp;

    SYS_PARAM_CHK((NULL == pEntry), SYS_ERR_NULL_POINTER);

    entry = SNMP_MALLOC_TYPEDEF(snmp_com2sec_t);
    if(!entry)
        return SYS_ERR_FAILED;

    osal_memset(entry,0,sizeof(snmp_com2sec_t));
    osal_strcpy(entry->comEntry.secName, pEntry->secName);
    osal_strcpy(entry->comEntry.comName, pEntry->comName);
    osal_strcpy(entry->comEntry.sourceNet, pEntry->sourceNet);
    osal_strcpy(entry->comEntry.mask, pEntry->mask);
    entry->comEntry.access = pEntry->access;
    entry->next = NULL;

    if (snmpComList == NULL)
        snmpComList = entry;
    else
    {
        pTmp = snmpComList;
        while(pTmp->next)
        {
            pTmp = pTmp->next;
        }
        pTmp->next = entry;
    }

    return SYS_ERR_OK;
}

int32 snmp_community_entry_get(uint32 *pEntryNum)
{
    sal_snmp_com2sec_t comEntry;
    uint32   entryNum = 0;
    int index;

    SYS_PARAM_CHK((NULL == pEntryNum), SYS_ERR_NULL_POINTER);

    snmp_community_removeAll();

     for ( index = 0; index < CAPA_SNMP_COMMUNITY_NUM; index++)
     {
        SYS_ERR_CHK(sal_snmp_com2sec_get(index, &comEntry));

        if (osal_strlen(comEntry.comName) != 0)
        {
            snmp_community_creatEntry(&comEntry);
            entryNum++;
        }
    }

    *pEntryNum = entryNum;
    return SYS_ERR_OK;
}


