unsigned char *
var_snmpCommunityTable(struct variable *vp,
            oid     *name,
            size_t  *length,
            int     exact,
            size_t  *var_len,
            WriteMethod **write_method)
{
    /* variables we may use later */
    static long long_ret;
    int32 entryNum, i, strLen;
    char comStr[CAPA_SNMP_COMMUNITY_LEN+1];
    snmp_com2sec_t  *pCom;
    static char tmpStr[BOND_SNMP_ENGINEID_LEN_MAX + 1];

    if (0 != AGUTIL_advance_index_name(vp, name, length, exact)) {
       return NULL;
    }

    if (exact) {
        if (*length < 12 || *length > 12+CAPA_SNMP_COMMUNITY_LEN)
            return NULL;

        osal_memset(comStr, 0, sizeof(comStr));
        for (i = 11; i < *length; i++)
        {
            if (name[i] >= 255)
                return NULL;
            comStr[i-11] = (char)name[i];
        }
        pCom = snmp_communityEntry_get(comStr);
    } else {
        if (11 == *length)
        {
            snmp_community_entry_get(&entryNum);
            if(entryNum == 0)
            return NULL;

            osal_memset(comStr, 0 , sizeof(comStr));
            pCom = snmp_community_scanFirst();
        }
        else
        {
            pCom = NULL;
            osal_memset(comStr, 0 , sizeof(comStr));

            if (*length < 12 || *length > 12+CAPA_SNMP_COMMUNITY_LEN)
                return NULL;

            for (i = 11; i < *length; i++)
            {
                if (name[i] >= 255)
                    return NULL;
                comStr[i-11] = (char)name[i];
            }

           snmp_community_scanAccessInit();
           while((pCom = snmp_community_scanAccessNext()) != NULL){
            if ((0 == osal_memcmp(comStr , pCom->comEntry.comName, *length - 11 )) &&
                     (osal_strlen( pCom->comEntry.comName) == osal_strlen(comStr)))
             {
                 pCom = snmp_community_scanAccessNext();
                 break;
             }
           }
         }

        if (pCom) {
            strLen = osal_strlen(pCom->comEntry.comName);
            for (i = 0; i < strLen; i++)
            {
                name[11 + i] = (uint32)(pCom->comEntry.comName[i]);
            }
            *length = 11 + strLen;
        }
    }

    if (pCom == NULL) {
        return NULL;
    }

    *var_len = sizeof(long_ret);
    /*
   * this is where we do the value assignments for the mib results.
   */
    switch(vp->magic) {
    case SNMPCOMMUNITYINDEX:
        #if 0
        *var_len = osal_strlen(pCom->comEntry.comName);
        return (u_char*)pCom->comEntry.comName;
        #endif
        return NULL;
    case SNMPCOMMUNITYNAME:
        *write_method = write_snmpCommunityName;
        SYS_MEM_CLEAR(tmpStr);
        osal_strcpy(tmpStr, pCom->comEntry.comName);
        *var_len = osal_strlen(tmpStr);
        return (u_char*)tmpStr;
    case SNMPCOMMUNITYSECURITYNAME:
        *write_method = write_snmpCommunitySecurityName;
        SYS_MEM_CLEAR(tmpStr);
        osal_strcpy(tmpStr, pCom->comEntry.secName);
        *var_len = osal_strlen(tmpStr);
        return (u_char*)tmpStr;
    case SNMPCOMMUNITYCONTEXTENGINEID:
        *write_method = write_snmpCommunityContextEngineID;
        SYS_MEM_CLEAR(tmpStr);
        #ifdef CONFIG_SYS_SNMPV3
        sal_snmp_engineid_get(tmpStr);
        #endif
        *var_len = osal_strlen(tmpStr);
        return (u_char*) tmpStr;
    case SNMPCOMMUNITYCONTEXTNAME:
        *write_method = write_snmpCommunityContextName;
        *var_len = 0;
        osal_memset(tmpStr, 0, sizeof(tmpStr));
        return (u_char*)tmpStr;
    case SNMPCOMMUNITYTRANSPORTTAG:
        *write_method = write_snmpCommunityTransportTag;
        *var_len = 0;
        osal_memset(tmpStr, 0, sizeof(tmpStr));
        return (u_char*)tmpStr;
    case SNMPCOMMUNITYSTORAGETYPE:
        *write_method = write_snmpCommunityStorageType;
        long_ret  = SNMP_STORAGE_NONVOLATILE;
        return (u_char*) &long_ret;
    case SNMPCOMMUNITYSTATUS:
        *write_method = write_snmpCommunityStatus;
        long_ret = 1;
        return (u_char*) &long_ret;
    default:
      ERROR_MSG("");
    }
    return NULL;
}
