          if (var_val_len > sizeof(long)) {
              fprintf(stderr,"write to snmpCommunityMIB: bad length\n");
              return SNMP_ERR_WRONGLENGTH;
          }
          break;

        case RESERVE2:
          size  = var_val_len;
          value = * (long *) var_val;

